const items = $input.all();
const operators = [
  { name: 'mellamusic73@gmail.com', data: items[0]?.json || {} },
  { name: 'markethub973@gmail.com',  data: items[1]?.json || {} },
];

const renderOne = (op) => {
  const d = op.data || {};
  const state = d.state || {};
  const recs = d.recommendations || [];
  const recsHtml = recs.map((r, i) => `
    <div style="margin:12px 0;padding:10px;border-left:3px solid ${
      r.priority === 'high' ? '#dc2626' : r.priority === 'medium' ? '#f59e0b' : '#10b981'
    };background:#fafafa;">
      <div style="font-weight:bold;font-size:13px;">${i+1}. ${r.action}</div>
      <div style="color:#555;font-size:12px;margin-top:4px;"><b>Why:</b> ${r.why}</div>
      <div style="color:#777;font-size:11px;margin-top:4px;">
        Tool: <b>${r.tool}</b> · Priority: <b>${r.priority}</b> · Est. ${r.estimated_hours ?? '?'}h
        · <a href="https://markethubpromo.com${r.app_path}">Open</a>
      </div>
    </div>`).join('');
  return `
    <h2 style="margin:24px 0 8px;border-bottom:1px solid #ddd;padding-bottom:6px;">👤 ${op.name}</h2>
    <p style="color:#555;font-size:13px;margin:0 0 12px;">${d.summary_headline || ''}</p>
    <div style="background:#f3f4f6;padding:10px;border-radius:6px;font-size:12px;">
      <b>State:</b> MRR $${state.mrr_usd ?? 0} · Users ${state.total_users ?? 0} (paying ${state.paying_users ?? 0}, trial ${state.trial_users ?? 0})
      · Leads ${state.leads_total ?? 0} (+${state.leads_new_7d ?? 0} 7d)
      · Posts 30d ${state.published_posts_30d ?? 0} · Scheduled 7d ${state.scheduled_posts_next_7d ?? 0}
      · AI assets 30d ${state.ai_assets_30d ?? 0}
    </div>
    <h3 style="margin:16px 0 4px;font-size:14px;">Top ${recs.length} actions</h3>
    ${recsHtml}`;
};

const html = `
  <div style="font-family:system-ui,-apple-system,sans-serif;max-width:720px;margin:0 auto;padding:20px;color:#222;">
    <h1 style="margin:0 0 4px;font-size:20px;">🧠 CEO Brain — Daily Digest</h1>
    <p style="color:#888;font-size:11px;margin:0 0 12px;">${new Date().toLocaleDateString('ro-RO', { weekday:'long', year:'numeric', month:'long', day:'numeric' })}</p>
    ${operators.map(renderOne).join('')}
    <p style="color:#999;font-size:11px;margin-top:24px;">Generated: ${new Date().toISOString()}</p>
  </div>`;

return [{ json: {
  subject: `CEO Brain daily digest — ${new Date().toLocaleDateString()}`,
  html,
  to: 'eduard@markethubpromo.com'
} }];
